/**
 * MedX switch runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Toggles feature flags and operational modes for the supply-chain dashboard.
 */
const SWITCH_FEATURES = Object.freeze({
  coldChainMonitoring: {
    label: "Cold chain monitoring",
    description: "Enable real-time temperature alerts for refrigerated inventory",
    defaultOn: true,
    category: "operations",
  },
  blockchainTrace: {
    label: "Blockchain traceability",
    description: "Record lot movements on-chain for audit trail",
    defaultOn: false,
    category: "compliance",
  },
  autoReorder: {
    label: "Automatic reorder",
    description: "Trigger purchase orders when stock falls below threshold",
    defaultOn: true,
    category: "inventory",
  },
  darkMode: {
    label: "Dark mode",
    description: "Use dark theme across dashboard surfaces",
    defaultOn: false,
    category: "appearance",
  },
  betaAnalytics: {
    label: "Beta analytics",
    description: "Enable experimental demand forecasting charts",
    defaultOn: false,
    category: "experimental",
  },
  walletConnect: {
    label: "Wallet connect",
    description: "Allow Web3 wallet authentication for suppliers",
    defaultOn: false,
    category: "integrations",
  },
});

const switchState = new Map();
const switchListeners = new Set();

function initSwitches() {
  for (const [key, meta] of Object.entries(SWITCH_FEATURES)) {
    switchState.set(key, {
      key,
      enabled: meta.defaultOn,
      ...meta,
      lastToggledAt: null,
    });
  }
}

function getSwitch(key) {
  return switchState.get(key) ?? null;
}

function setSwitch(key, enabled, source = "api") {
  const entry = switchState.get(key);
  if (!entry) return false;
  const previous = entry.enabled;
  entry.enabled = Boolean(enabled);
  entry.lastToggledAt = Date.now();
  entry.lastSource = source;
  notifySwitchListeners({ key, previous, current: entry.enabled, source });
  return true;
}

function toggleSwitch(key, source = "user") {
  const entry = switchState.get(key);
  if (!entry) return false;
  return setSwitch(key, !entry.enabled, source);
}

function onSwitchChange(listener) {
  if (typeof listener !== "function") return () => {};
  switchListeners.add(listener);
  return () => switchListeners.delete(listener);
}

function notifySwitchListeners(event) {
  for (const listener of switchListeners) {
    try {
      listener(event);
    } catch (err) {
      console.warn("[medx:ui:switch] listener error", err.message);
    }
  }
}

function getSwitchesByCategory(category) {
  return Array.from(switchState.values()).filter((s) => s.category === category);
}

function exportSwitchConfig() {
  const result = {};
  for (const [key, entry] of switchState) {
    result[key] = entry.enabled;
  }
  return result;
}

async function runMedxSwitch() {
  console.log("[medx:ui:switch] runtime initialized");
  initSwitches();

  const changes = [];
  onSwitchChange((event) => changes.push(event));

  toggleSwitch("blockchainTrace");
  setSwitch("betaAnalytics", true, "bootstrap");
  setSwitch("darkMode", true, "bootstrap");

  const operations = getSwitchesByCategory("operations");
  const config = exportSwitchConfig();
  const enabledCount = Object.values(config).filter(Boolean).length;

  console.log(`[medx:ui:switch] features=${switchState.size} enabled=${enabledCount}`);
  console.log(`[medx:ui:switch] operations=${operations.map((s) => s.key).join(",")}`);
  console.log(`[medx:ui:switch] changeEvents=${changes.length}`);
  console.log("[medx:ui:switch] bootstrap complete");
}

module.exports = runMedxSwitch;
